ppu_team = { "BalatrosAPalindrome" },
	key = "bap_nothing",
	set = 'Planet',
	cost = 3,
	atlas = 'Palindrome',
	pos = { x = 0, y = 0 },
	config = { hand_type = "worm_bap_void" },
	in_pool = function(self, args)
		return SMODS.is_poker_hand_visible("worm_bap_void")
	end,
	loc_vars = function(self, info_queue, card)
		if not SMODS.is_poker_hand_visible("worm_bap_void") then
			return {
				vars = {
					"0",
					"Nothing??",
					"0",
					"0",
					colours = { G.C.UI.TEXT_DARK }
				}
			}
		end

		return {
			vars = {
				G.GAME.hands[card.ability.hand_type or 'High Card'].level,
				"Void Hand",
				G.GAME.hands[card.ability.hand_type or 'High Card'].l_mult,
				G.GAME.hands[card.ability.hand_type or 'High Card'].l_chips,
				colours = { (G.GAME.hands[card.ability.hand_type or 'High Card'].level == 1 and G.C.UI.TEXT_DARK or G.C.HAND_LEVELS[math.min(7, G.GAME.hands[card.ability.hand_type or 'High Card'].level)]) }
			}
		}
	end,
	can_use = function(self, card)
		if not SMODS.is_poker_hand_visible("worm_bap_void") then
			card.ability.hand_type = ""
		else
			card.ability.hand_type = "worm_bap_void"
		end
		return SMODS.is_poker_hand_visible("worm_bap_void")
	end

key = "dum_crystalsphere",
    attributes = {"chance", "retrigger", "face", "space"},
    config = { extra = { odds = 3 } },
    loc_vars = function(self, info_queue, card)
        local num, denom = SMODS.get_probability_vars(card, 1, card.ability.extra.odds, "dum_crystalsphere")
        return { vars = { num, denom } }
    end,
    rarity = 1,
    atlas = 'DummiesJokers',
    pos = { x = 0, y = 2 },
    wormhole_pos_extra = { hand_a = { x = 1, y = 2 }, hand_b = { x = 5, y = 2 }, ball = { x = 9, y = 2 } },
    wormhole_anim_extra = {
        hand_a = {
            { xrange = { first = 1, last = 4 }, y = 2, t = 0.3 }
        },
        hand_b = {
            { x = 5, y = 2, t = 0.15 },
            { xrange = { first = 6, last = 8 }, y = 2, t = 0.3 },
            { x = 5, y = 2, t = 0.15 }
        },
        ball = {
            { x = 9, y = 2, t = 3 },
            { xrange = { first = 10, last = 11 }, y = 2, t = 0.075 },
            { xrange = { first = 0, last = 2 }, y = 3, t = 0.075 },
            { x = 9, y = 2, t = 5 },
        },
    },
    cost = 4,
    blueprint_compat = true,
    eternal_compat = true,
    perishable_compat = true,
    calculate = function(self, card, context)
        if context.before and not context.blueprint then
            local found_face = false
            for _, v in ipairs(context.scoring_hand) do
                if v:is_face() then found_face = true break end
            end

            card.ability.extra.found_face = found_face and SMODS.pseudorandom_probability(card, "dum_crystalsphere", 1, card.ability.extra.odds)
        end

        if context.repetition and context.cardarea == G.play and not context.end_of_round and card.ability.extra.found_face then
            return { repetitions = 1 }
        end
    end,
    pronouns = "it_its",

    ppu_team = { "dummies" },
    ppu_artist = { "ghostsalt" },
    ppu_coder = { "ghostsalt" }

