                        nodes = {
                            { n = G.UIT.T, config = { text = ' ' .. last_constellation .. ' ', colour = G.C.UI.TEXT_LIGHT, scale = 0.3, shadow = true } },
                        }
                    }
                }
            }
            }
        }
    end,
