    ppu_artist = { 'RadiationV2' },
    ppu_team = { 'ACME' },
    keep_on_use = function(self, card)
        return true
    end,
    set_ability = function(self, card, initial, delay_sprites)
        if initial then
            card.ability.extra = {
                last_ante_used = 0,
                completed = false,
                effect_used = false,
                times_completed = 0,
            }
        end
    end,
    config = {
        extra = {
            last_ante_used = 0,
            completed = false,
            effect_used = false,
            times_completed = 0,
        }
    },
    loc_vars = function(self, info_queue, card)
        local e = card.ability.extra
        local ante = G.GAME and G.GAME.round_resets and G.GAME.round_resets.ante or 0
        if e.completed and e.last_ante_used == ante and not e.effect_used then
            return { key = self.key .. '_alt' }
        else
            return { vars = {} }
        end
    end,
    can_use = function(self, card)
        if not G.GAME or not G.GAME.round_resets then return false end
        local e = card.ability.extra
        local ante = G.GAME.round_resets.ante

        if e.completed and e.last_ante_used == ante and not e.effect_used then
            return G.hand and #G.hand.highlighted == 5
        else
            return e.last_ante_used ~= ante
        end
    end,
    use = function(self, card, area, copier)
        local e = card.ability.extra
        local ante = G.GAME.round_resets.ante

        if e.completed and e.last_ante_used == ante and not e.effect_used then
            -- kaboom
            e.effect_used = true
            local destroyed = {}
            for i = 1, #G.hand.highlighted do
                destroyed[#destroyed + 1] = G.hand.highlighted[i]
            end

            G.E_MANAGER:add_event(Event({
                trigger = 'after',
                delay = 0.4,
                func = function()
                    play_sound('tarot1')
                    card:juice_up(0.3, 0.5)
                    return true
                end,
            }))

            for i = 1, #destroyed do
                G.E_MANAGER:add_event(Event({
                    trigger = 'after',
                    delay = 0.12,
                    func = function()
                        play_sound('card1', 0.75 + i * 0.05)
                        destroyed[i]:start_dissolve(nil, true)
                        return true
                    end,
                }))
            end

            G.E_MANAGER:add_event(Event({
                trigger = 'after',
                delay = 0.3,
                func = function()
                    card_eval_status_text(card, 'extra', nil, nil, nil, {
                        message = localize('k_acme_bombs_complete'),
                        colour = G.C.RED,
                    })
                    return true
                end,
            }))
        else
            -- open minigame
            e.completed = false
            e.effect_used = false
            G.E_MANAGER:add_event(Event({
                trigger = 'after',
                delay = 0.4,
                func = function()
                    play_sound('tarot1')
                    card:juice_up(0.3, 0.5)
                    return true
                end,
            }))
            G.E_MANAGER:add_event(Event({
                trigger = 'after',
                delay = 0.2,
                func = function()
                    open_bomb_game(card)
                    return true
                end,
            }))
        end
    end,
    calculate = function(self, card, context)
        -- no scoring here
    end,

key = 'acme_gas_station',
	atlas = 'ACME_jokers',
	rarity = 3,
